import React, { useState, useEffect } from 'react';
import { obtenerProductos, guardarProducto } from '../services/productoService';

const Inventario = () => {
    const [productos, setProductos] = useState([]);
    const [nuevoProd, setNuevoProd] = useState({
        codigo: '', nombre: '', stock: 0, precioCompra: 0, precioVenta: 0, categoria: 'Fundas'
    });

    // Cargar productos al entrar a la página
    useEffect(() => {
        cargarProductos();
    }, []);

    const cargarProductos = async () => {
        const data = await obtenerProductos();
        setProductos(data);
    };

    const handleGuardar = async (e) => {
        e.preventDefault();
        // Agregamos tu matrícula para que quede el registro en el backend
        const productoConAutor = { ...nuevoProd, registradoPorMatricula: 'riempy' };
        await guardarProducto(productoConAutor);
        setNuevoProd({ codigo: '', nombre: '', stock: 0, precioCompra: 0, precioVenta: 0, categoria: 'Fundas' });
        cargarProductos();
    };

    return (
        <div style={{ padding: '20px', fontFamily: 'Arial' }}>
            <h2>📦 Inventario - Isla Tecnológica</h2>
            
            {/* Formulario para agregar productos */}
            <form onSubmit={handleGuardar} style={{ marginBottom: '30px', border: '1px solid #ccc', padding: '15px' }}>
                <h3>Agregar Nuevo Producto</h3>
                <input placeholder="Código" value={nuevoProd.codigo} onChange={e => setNuevoProd({...nuevoProd, codigo: e.target.value})} required />
                <input placeholder="Nombre (Funda, Mica...)" value={nuevoProd.nombre} onChange={e => setNuevoProd({...nuevoProd, nombre: e.target.value})} required />
                <input type="number" placeholder="Stock" value={nuevoProd.stock} onChange={e => setNuevoProd({...nuevoProd, stock: parseInt(e.target.value)})} required />
                <input type="number" step="0.01" placeholder="Precio Compra" value={nuevoProd.precioCompra} onChange={e => setNuevoProd({...nuevoProd, precioCompra: parseFloat(e.target.value)})} required />
                <input type="number" step="0.01" placeholder="Precio Venta" value={nuevoProd.precioVenta} onChange={e => setNuevoProd({...nuevoProd, precioVenta: parseFloat(e.target.value)})} required />
                <button type="submit" style={{ backgroundColor: '#28a745', color: 'white', cursor: 'pointer' }}>Guardar Producto</button>
            </form>

            {/* Tabla de Productos */}
            <table border="1" width="100%" style={{ textAlign: 'left', borderCollapse: 'collapse' }}>
                <thead style={{ backgroundColor: '#f4f4f4' }}>
                    <tr>
                        <th>Código</th>
                        <th>Nombre</th>
                        <th>Stock</th>
                        <th>Costo ($)</th>
                        <th>Venta ($)</th>
                        <th>Ganancia Unidad ($)</th>
                        <th>Categoría</th>
                    </tr>
                </thead>
                <tbody>
                    {productos.map(p => (
                        <tr key={p.id}>
                            <td>{p.codigo}</td>
                            <td>{p.nombre}</td>
                            <td style={{ color: p.stock < 5 ? 'red' : 'black' }}>{p.stock}</td>
                            <td>{p.precioCompra}</td>
                            <td>{p.precioVenta}</td>
                            <td style={{ fontWeight: 'bold', color: 'green' }}>
                                {(p.precioVenta - p.precioCompra).toFixed(2)}
                            </td>
                            <td>{p.categoria}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

export default Inventario;
